namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Title is required.")]
    public string Title { get; set; } = "";

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = "";

    [Required(ErrorMessage = "Ingredients are required.")]
    public string Ingredients { get; set; } = "";

    [Required(ErrorMessage = "Steps are required.")]
    public string Steps { get; set; } = "";

    public string Description { get; set; } = "";
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new Recipe
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Description = "Fluffy homemade pancakes perfect for a weekend morning.",
                Ingredients = new List<string> { "1 cup flour", "1 egg", "1 cup milk", "2 tbsp sugar", "1 tsp baking powder", "Pinch of salt" },
                Steps = new List<string> { "Mix dry ingredients together.", "Whisk egg and milk, then combine with dry mix.", "Heat a skillet over medium heat and grease lightly.", "Pour batter and cook until bubbles form, then flip.", "Serve with syrup and butter." },
                TotalRatings = 3, RatingSum = 13
            },
            new Recipe
            {
                Id = 2, Title = "Avocado Toast", Category = "Breakfast",
                Description = "Simple and healthy avocado toast with a kick of lemon.",
                Ingredients = new List<string> { "2 slices bread", "1 ripe avocado", "Lemon juice", "Salt and pepper", "Red pepper flakes" },
                Steps = new List<string> { "Toast the bread until golden.", "Mash the avocado and season with lemon juice, salt, and pepper.", "Spread avocado on toast and sprinkle red pepper flakes." },
                TotalRatings = 2, RatingSum = 8
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Main Course",
                Description = "A rich and hearty Italian meat sauce over spaghetti.",
                Ingredients = new List<string> { "400g spaghetti", "500g ground beef", "1 onion", "2 cloves garlic", "400ml crushed tomatoes", "2 tbsp olive oil", "Salt and pepper", "Fresh basil" },
                Steps = new List<string> { "Cook spaghetti according to package directions.", "Sauté onion and garlic in olive oil.", "Add ground beef and cook until browned.", "Stir in crushed tomatoes, salt, and pepper. Simmer 20 minutes.", "Serve sauce over spaghetti and garnish with basil." },
                TotalRatings = 5, RatingSum = 22
            },
            new Recipe
            {
                Id = 4, Title = "Grilled Chicken Salad", Category = "Main Course",
